SELECT /* base.ec.cm :: CmBlogFile :: selectList */ f.* , blt.blog_title AS blog_nm FROM cm_blog_file f LEFT JOIN cm_blog blt ON blt.blog_id = f.blog_id
ORDER BY f.blog_img_id ASC ORDER BY f.blog_img_id DESC ORDER BY f.reg_date ASC ORDER BY f.reg_date DESC ORDER BY f.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT /* base.ec.cm :: CmBlogFile :: selectPageList */ f.* , blt.blog_title AS blog_nm FROM cm_blog_file f LEFT JOIN cm_blog blt ON blt.blog_id = f.blog_id
ORDER BY f.blog_img_id ASC ORDER BY f.blog_img_id DESC ORDER BY f.reg_date ASC ORDER BY f.reg_date DESC ORDER BY f.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

mapper.update:
UPDATE cm_blog_file /* base.ec.cm :: CmBlogFile :: updateSelective */
blog_id = #{blogId}, img_url = #{imgUrl}, thumb_url = #{thumbUrl}, img_alt_text = #{imgAltText}, sort_ord = #{sortOrd},
WHERE blog_img_id = #{blogImgId}
